/**
 * Get or create user by email (for student self-enrollment)
 * Returns user record that can be used for exam attempts
 *
 * Phase 1.2: Student enrollment helper
 * Handles race condition when two students join simultaneously with same email
 */
async getOrCreateUserByEmail(email: string, name: string): Promise<{ id: number }> {
  // Try to find existing user
  const existingResult = await this.pg.query(
    'SELECT id FROM users WHERE email = $1',
    [email]
  );

  if (existingResult.rows.length > 0) {
    return { id: existingResult.rows[0].id };
  }

  // Create new user with student role
  try {
    const insertResult = await this.pg.query(
      `INSERT INTO users (moodle_user_id, username, email, first_name, last_name, role)
       VALUES ($1, $2, $3, $4, $5, 'student')
       RETURNING id`,
      [Date.now(), email.split('@')[0], email, name, ''] // Generate moodle_user_id from timestamp
    );

    return { id: insertResult.rows[0].id };
  } catch (error: any) {
    // Handle race condition: another thread created the user between our SELECT and INSERT
    if (error.code === '23505') {
      // Unique violation - retry SELECT to get the user that won the race
      const retryResult = await this.pg.query(
        'SELECT id FROM users WHERE email = $1',
        [email]
      );

      if (retryResult.rows.length > 0) {
        return { id: retryResult.rows[0].id };
      }

      // Shouldn't happen, but throw if it does
      throw new Error(`Failed to create or retrieve user for email: ${email}`);
    }

