let roomEnrollment = null

function getRoomEnrollment() {
  try {
    const stored = localStorage.getItem('roomEnrollment')
    if (stored) {
      return JSON.parse(stored)
    }
  } catch (error) {
    console.error('Error parsing room enrollment:', error)
  }
  return null
}

