  return {
    warningCount: liveAiWarnings.length,
    advisoryCount: liveAiAdvisories.length,
    hasWarnings,
    hasAdvisories,
    normalizedState: hasWarnings
      ? 'warning'
      : hasAdvisories
      ? 'running'
      : aiProctoringStatus.state || 'idle'
  }
