// ============================================================================
// Room Module - Service Layer
// Proctoring room lifecycle management
// ============================================================================

import { Pool } from 'pg';
import { randomBytes, createHmac } from 'crypto';

/**
 * Sanitize user input to prevent XSS attacks
 * Strips HTML tags and dangerous characters
 */
function sanitizeInput(input: string): string {
  // Remove HTML tags
  return input
    .replace(/<[^>]*>/g, '') // Remove HTML tags
    .replace(/javascript:/gi, '') // Remove javascript: protocol
    .replace(/on\w+\s*=/gi, '') // Remove event handlers like onclick=
    .trim();
}

/**
 * Generate HMAC signature for enrollment data
 * Prevents tampering with enrollment IDs in localStorage
 */
function generateEnrollmentSignature(enrollmentId: number, roomId: number, secret: string): string {
  const data = `${enrollmentId}:${roomId}`;
  return createHmac('sha256', secret)
    .update(data)
    .digest('hex');
}

/**
 * Validate HMAC signature for enrollment data
 */
function validateEnrollmentSignature(
  enrollmentId: number,
  roomId: number,
  signature: string,
  secret: string
): boolean {
  const expectedSignature = generateEnrollmentSignature(enrollmentId, roomId, secret);
  return signature === expectedSignature;
}

